import pickle
import json
import os
from typing import Any, Dict, List, Union

class SecurePickler:
    @staticmethod
    def save_preferences(data: Any, filepath: str) -> None:
        """Save preferences to file using secure pickle with protocol 4."""
        try:
            with open(filepath, 'wb') as f:
                pickle.dump(data, f, protocol=pickle.HIGHEST_PROTOCOL)
        except Exception as e:
            raise IOError(f"Failed to save preferences: {e}")
    
    @staticmethod
    def load_preferences(filepath: str) -> Any:
        """Load preferences from file with security checks."""
        if not os.path.exists(filepath):
            raise FileNotFoundError(f"Preferences file not found: {filepath}")
        
        try:
            with open(filepath, 'rb') as f:
                data = pickle.load(f)
                # Security check: ensure no dangerous objects are loaded
                SecurePickler._validate_loaded_data(data)
                return data
        except Exception as e:
            raise IOError(f"Failed to load preferences: {e}")
    
    @staticmethod
    def _validate_loaded_data(data: Any) -> None:
        """Validate that loaded data doesn't contain dangerous objects."""
        def _check(obj):
            if isinstance(obj, type):
                raise ValueError("Cannot load type objects")
            if hasattr(obj, '__reduce__') and hasattr(obj, '__reduce_ex__'):
                # Check for potentially dangerous classes
                if obj.__module__ in ('os', 'sys', 'subprocess', 'pickle', 'marshal'):
                    raise ValueError("Security violation: dangerous object loaded")
            if isinstance(obj, (dict, list)):
                for item in (obj.values() if isinstance(obj, dict) else obj):
                    _check(item)
        
        _check(data)

# Alternative JSON-based approach for better compatibility
class JSONPreferences:
    @staticmethod
    def save_preferences(data: Any, filepath: str) -> None:
        """Save preferences to JSON file."""
        try:
            with open(filepath, 'w') as f:
                json.dump(data, f, indent=2, default=str)
        except Exception as e:
            raise IOError(f"Failed to save preferences: {e}")
    
    @staticmethod
    def load_preferences(filepath: str) -> Any:
        """Load preferences from JSON file."""
        if not os.path.exists(filepath):
            raise FileNotFoundError(f"Preferences file not found: {filepath}")
        
        try:
            with open(filepath, 'r') as f:
                return json.load(f)
        except Exception as e:
            raise IOError(f"Failed to load preferences: {e}")

